import { describe, it, expect } from "vitest";
import { readdirSync, readFileSync } from "node:fs";
import { join } from "node:path";

/**
 * Drift guard for netlify/functions/_migrations.json
 *
 * The bundle is generated by scripts/bundle-migrations.js (auto-runs on
 * `npm run prebuild`). When a new .sql file lands in supabase/migrations/
 * but the bundle isn't regenerated and committed, run-migrations.js ships
 * a stale list and the git working tree shows mysterious modifications on
 * the next `npm install` / build.
 *
 * Mirrors PR #166's inline CSP hash regression: pin the build artifact to
 * its source, fail CI on drift.
 */

const ROOT = join(import.meta.dirname, "..");
const MIGRATIONS_DIR = join(ROOT, "supabase", "migrations");
const BUNDLE = join(ROOT, "netlify", "functions", "_migrations.json");

describe("migrations bundle drift", () => {
  it("_migrations.json matches the .sql files in supabase/migrations/", () => {
    // Recompute what scripts/bundle-migrations.js would produce. Keep the
    // logic byte-identical to the bundler so this test is a true mirror.
    const files = readdirSync(MIGRATIONS_DIR)
      .filter(f => f.endsWith(".sql"))
      .sort();

    const expected = files.map(f => ({
      name: f.replace(/\.sql$/, ""),
      sql: readFileSync(join(MIGRATIONS_DIR, f), "utf-8").replace(/\r\n/g, "\n"),
    }));

    const actual = JSON.parse(readFileSync(BUNDLE, "utf-8"));

    // Names first — the cheap check that gives the most actionable failure.
    expect(actual.map(m => m.name)).toEqual(expected.map(m => m.name));

    // Full structural equality — catches sql-content drift too (e.g. someone
    // edits a migration .sql in place without regenerating).
    expect(actual).toEqual(expected);
  });
});
